#Preprocessorsimport numpy as npimport osimport matplotlib.pyplot as pltfrom ramanspy.preprocessing.denoise import SavGolfrom sklearn.pipeline import make_pipelineimport chemometrics as cmimport ramanspyfrom ramanspy.preprocessing.misc import Cropperfrom scipy.signal import savgol_filterfrom collections import defaultdictdef preprocess_pipeline_1(sample_spectra, spectra_dir, crop_region=(500, 1800), savgol_window=9, savgol_polyorder=2, emsc_p_order=2, emsc_asym_factor=0.1):    """    Preprocesses Raman spectra using cropping, Savitzky-Golay smoothing, and EMSC.    Parameters:        sample_spectra (dict): Dictionary where keys are sample names and values are lists of spectra.                                This is the output of the load raman function        spectra_dir (str): Path to the directory where preprocessed spectra plots will be saved.        crop_region (tuple): Region to crop the spectra (start, end) in cm⁻¹.        savgol_window (int): Window length for Savitzky-Golay smoothing.        savgol_polyorder (int): Polynomial order for Savitzky-Golay smoothing.        emsc_p_order (int): Polynomial order for EMSC.        emsc_asym_factor (float): Asymmetry factor for EMSC.    Returns:        sample_spectra (dict): Dictionary with preprocessed spectra.        cropped_axis (list): cropped spectral axis    """    # Create the spectra directory if it doesn't exist    os.makedirs(spectra_dir, exist_ok=True)    # Iterate over each sample and its spectra    for sample_name, spectra in sample_spectra.items():        cropped_spectra = []  # Create a new list to store cropped spectra for this sample        cropped_axis = None        for spectrum in spectra:            # Crop the spectrum            cropper = Cropper(region=crop_region)            cropped_spectrum = cropper.apply(spectrum)            cropped_spectra.append(cropped_spectrum)            if cropped_axis is None:                cropped_axis = cropped_spectrum.spectral_axis                    # Apply Savitzky-Golay smoothing        savgol = SavGol(window_length=savgol_window, polyorder=savgol_polyorder, deriv=0)        smoothed_spectra = savgol.apply(cropped_spectra)        # Convert spectra y values to an array for EMSC processing        spectral_data = np.array([spectrum.spectral_data for spectrum in smoothed_spectra])  # Shape: (n_spectra, n_points)        # Apply EMSC preprocessing        pipeline = make_pipeline(cm.Emsc(p_order=emsc_p_order, background=None, normalize=False, algorithm='als', asym_factor=emsc_asym_factor))        spectra_emsc = pipeline.fit_transform(spectral_data)        # Convert the EMSC-corrected data back into ramanspy.Spectrum objects        emsc_spectra = [            ramanspy.Spectrum(spectrum_data, cropped_spectra[0].spectral_axis)  # Use the same spectral axis as the cropped spectra            for spectrum_data in spectra_emsc        ]        # Replace the original spectra with the EMSC-corrected spectra in sample_spectra dictionary        sample_spectra[sample_name] = emsc_spectra        # Save cropped spectra for this sample        plt.figure(figsize=(8, 5))        for cropped_spectrum in cropped_spectra:            plt.plot(cropped_spectrum.spectral_axis, cropped_spectrum.spectral_data, label=f"{sample_name} (Cropped)", color="blue", alpha=0.5)        plt.title(f"Cropped Spectra: {sample_name}")        plt.xlabel("Raman Shift (cm⁻¹)")        plt.ylabel("Intensity")        plt.legend()        individual_plot_path = os.path.join(spectra_dir, f"{sample_name}_Cropped.png")        plt.savefig(individual_plot_path, dpi=300, bbox_inches="tight")        plt.close()        # Save the EMSC-corrected spectra for this sample        plt.figure(figsize=(8, 5))        for emsc_spectrum in emsc_spectra:            plt.plot(emsc_spectrum.spectral_axis, emsc_spectrum.spectral_data, label=f"{sample_name} (EMSC)", color="red")        plt.title(f"EMSC-Corrected Spectra: {sample_name}")        plt.xlabel("Raman Shift (cm⁻¹)")        plt.ylabel("Intensity")        plt.legend()        individual_plot_path = os.path.join(spectra_dir, f"{sample_name}_EMSCpreprocessed.png")        plt.savefig(individual_plot_path, dpi=300, bbox_inches="tight")        plt.close()       # Create a new figure for overlaying all spectra    plt.figure(figsize=(8, 5))    for sample_name, differentiated_spectra in sample_spectra.items():        for differentiated_spectrum in differentiated_spectra:            plt.plot(                differentiated_spectrum.spectral_axis,                 differentiated_spectrum.spectral_data,                 label=sample_name                  )    plt.title("Overlay of SavGol Derivative + SNV + Mean Centered Spectra")    plt.xlabel("Raman Shift (cm⁻¹)")    plt.ylabel("Intensity")    plt.legend(loc="best", ncol=2, fontsize="small")     plt.savefig(os.path.join(spectra_dir, "Overlay_Preprocessed.png"), dpi=300, bbox_inches="tight")    plt.close()        return sample_spectra, cropped_axisdef snv_normalization(spectral_data):    """    Apply Standard Normal Variate (SNV) normalization to the given spectral data.    SNV = (X - mean(X)) / std(X)        Parameters:        spectral_data (numpy.ndarray): The spectral data array to normalize.    Returns:        numpy.ndarray: The SNV-normalized spectral data.    """    # Center and scale each spectrum    mean_spectrum = np.mean(spectral_data, axis=1).reshape(-1, 1)  # Calculate mean for each spectrum    std_spectrum = np.std(spectral_data, axis=1).reshape(-1, 1)    # Calculate std for each spectrum        # Apply SNV normalization    snv_spectra = (spectral_data - mean_spectrum) / std_spectrum    return snv_spectradef mean_centering(spectral_data):    """    Apply mean centering to the spectral data by subtracting the mean of each spectrum.        Parameters:        spectral_data (numpy.ndarray): The spectral data array to mean-center.            Returns:        numpy.ndarray: The mean-centered spectral data.    """    mean_spectrum = np.mean(spectral_data, axis=1).reshape(-1, 1)  # Calculate mean for each spectrum    mean_centered_spectra = spectral_data - mean_spectrum    return mean_centered_spectradef preprocess_pipeline_2(sample_spectra, spectra_dir, crop_region=(800, 1800), derivative_order=1):    """    Preprocesses Raman spectra using cropping, Savitzky-Golay derivative (window length = 13), SNV normalization and mean centering    saves individual and overlaid preprocessed spectra    Parameters:        sample_spectra (dict): Dictionary where keys are sample names and values are lists of spectra.                                This is the output of the load raman function        spectra_dir (str): Path to the directory where preprocessed spectra plots will be saved.        crop_region (tuple): Region to crop the spectra (start, end) in cm⁻¹.        derivative order : the order of the savgol derivative    Returns:        sample_spectra (dict): Dictionary with preprocessed spectra.        cropped_axis (list): cropped spectral axis    """    # Iterate over each sample and its spectra    for sample_name, spectra in sample_spectra.items():        cropped_spectra = []  # Create a new list to store cropped spectra for this sample        differentiated_spectra = []  # List to store differentiated spectra for this sample        cropped_axis = None                for spectrum in spectra:            # Crop the spectrum            cropper = Cropper(region=crop_region)            cropped_spectrum = cropper.apply(spectrum)            cropped_spectra.append(cropped_spectrum)            if cropped_axis is None:                cropped_axis = cropped_spectrum.spectral_axis                        # Convert spectrum data to an array for processing            spectral_data = cropped_spectrum.spectral_data                        # Apply Savitzky-Golay filter (1st derivative) with a window size of 13            differentiated_spectrum_data = savgol_filter(spectral_data, polyorder=2, window_length=13, deriv=derivative_order)                        # Apply SNV normalization            snv_spectrum_data = snv_normalization(differentiated_spectrum_data.reshape(1, -1))  # SNV per spectrum                        # Apply mean centering            mean_centered_spectrum_data = mean_centering(snv_spectrum_data.reshape(1, -1))                        # Create a new Spectrum object with the mean-centered data            mean_centered_spectrum = ramanspy.Spectrum(mean_centered_spectrum_data.flatten(), cropped_spectrum.spectral_axis)            differentiated_spectra.append(mean_centered_spectrum)                # Replace the original spectra with the differentiated, SNV-normalized, and mean-centered spectra for this sample        sample_spectra[sample_name] = differentiated_spectra                # Plot the mean-centered, SNV-normalized, and Savitzky-Golay differentiated spectra        plt.figure(figsize=(8, 5))        for differentiated_spectrum in differentiated_spectra:            plt.plot(differentiated_spectrum.spectral_axis, differentiated_spectrum.spectral_data, label=f"{sample_name} (SavGol + SNV + Mean Centered)", color="red")        plt.title(f"SavGol Derivative + SNV + Mean Centered: {sample_name}")        plt.xlabel("Raman Shift (cm⁻¹)")        plt.ylabel("Intensity")        plt.legend()                # Save the plot for the current sample        individual_plot_path = os.path.join(spectra_dir, f"{sample_name}_Savgol_SNV_MeanCentered.png")        plt.savefig(individual_plot_path, dpi=300, bbox_inches="tight")        plt.close()        # Create a new figure for overlaying all spectra    plt.figure(figsize=(8, 5))    for sample_name, differentiated_spectra in sample_spectra.items():        for differentiated_spectrum in differentiated_spectra:            plt.plot(                differentiated_spectrum.spectral_axis,                 differentiated_spectrum.spectral_data,                 label=sample_name                  )    plt.title("Overlay of SavGol Derivative + SNV + Mean Centered Spectra")    plt.xlabel("Raman Shift (cm⁻¹)")    plt.ylabel("Intensity")     plt.savefig(os.path.join(spectra_dir, "Overlay_Preprocessed.png"), dpi=300, bbox_inches="tight")    plt.close()        return sample_spectra, cropped_axisdef group_preprocess(sample_spectra, sample_groups, spectra_dir, crop_region=(500, 1800),                     emsc_p_order=6, emsc_asym_factor=0.1):        group_avg_spectra = {}    cropped_axis = None    for group_id, sample_ids in sample_groups.items():        cropped_spectra = []        for sid in sorted(sample_ids):            spectra = sample_spectra.get(sid)            for spectrum in spectra:                cropper = Cropper(region=crop_region)                cropped = cropper.apply(spectrum)                if cropped_axis is None:                    cropped_axis = cropped.spectral_axis                cropped_spectra.append(cropped.spectral_data)               # === EMSC ===        data_array = np.array(cropped_spectra)        pipeline = make_pipeline(cm.Emsc(p_order=emsc_p_order, background=None, normalize=False,                                         algorithm='als', asym_factor=emsc_asym_factor))                emsc_corrected = pipeline.fit_transform(data_array)                # === Average after EMSC ===        group_avg = np.mean(emsc_corrected, axis=0)        group_avg_spectra[group_id] = ramanspy.Spectrum(group_avg, cropped_axis)        # === Plot ===        plt.figure(figsize=(8, 5))        for i, spectrum in enumerate(emsc_corrected):            plt.plot(cropped_axis, spectrum, alpha=0.3, label=f"{group_id}-{i+1}")        plt.plot(cropped_axis, group_avg, color="black", linewidth=2, label=f"{group_id} Avg")        plt.title(f"Group {group_id} - EMSC Corrected + Averaged")        plt.xlabel("Raman Shift (cm⁻¹)")        plt.ylabel("Intensity")        plt.legend()        plt.savefig(os.path.join(spectra_dir, f"{group_id}_emsc_avg.png"), dpi=300, bbox_inches="tight")        plt.close()    return group_avg_spectra, cropped_axisdef group_preprocess_2(sample_spectra, sample_groups, spectra_dir="Group_Preprocessed_Averages",                       crop_region=(800, 1800), derivative_order=1):    """    Group-level preprocessing using Crop → Savitzky-Golay Derivative → SNV → Mean Centering.    Parameters:    -----------    sample_spectra : dict        Sample ID → list of ramanspy.Spectrum objects    sample_groups : dict        Group ID → list of sample IDs (e.g., '1': ['1-1', '1-2', '1-3'])    spectra_dir : str        Path to save individual and overlay plots    crop_region : tuple        Region to crop (start, end) in cm⁻¹    derivative_order : int        Derivative order for Savitzky-Golay filter    Returns:    --------    group_avg_spectra : dict        Group ID → averaged, preprocessed Spectrum object    cropped_axis : np.ndarray        Cropped spectral axis    """    os.makedirs(spectra_dir, exist_ok=True)    group_avg_spectra = {}    cropped_axis = None    for group_id, sample_ids in sample_groups.items():        preprocessed = []        for sid in sorted(sample_ids):            spectra = sample_spectra.get(sid)            if not spectra:                print(f"⚠️ Sample '{sid}' missing or has no spectra. Skipping.")                continue            for spectrum in spectra:                # Crop                cropper = Cropper(region=crop_region)                cropped = cropper.apply(spectrum)                if cropped_axis is None:                    cropped_axis = cropped.spectral_axis                y = cropped.spectral_data                # Savitzky-Golay derivative                y_deriv = savgol_filter(y, polyorder=2, window_length=13, deriv=derivative_order)                # SNV normalization                y_snv = snv_normalization(y_deriv.reshape(1, -1))                # Mean centering                y_mc = mean_centering(y_snv).flatten()                preprocessed.append(y_mc)        if not preprocessed:            print(f"⚠️ Group '{group_id}' has no valid spectra. Skipping.")            continue        # Average preprocessed spectra        group_array = np.array(preprocessed)        avg = np.mean(group_array, axis=0)        group_avg_spectra[group_id] = ramanspy.Spectrum(avg, cropped_axis)        # Plot        plt.figure(figsize=(8, 5))        for i, y_proc in enumerate(group_array):            plt.plot(cropped_axis, y_proc, alpha=0.3, label=f"{group_id}-{i+1}")        plt.plot(cropped_axis, avg, color="black", linewidth=2, label=f"{group_id} Avg")        plt.title(f"Group {group_id} - SavGol Deriv + SNV + Mean Centered")        plt.xlabel("Raman Shift (cm⁻¹)")        plt.ylabel("Intensity")        plt.legend()        plt.savefig(os.path.join(spectra_dir, f"{group_id}_deriv_snv_meancentered_avg.png"), dpi=300, bbox_inches="tight")        plt.close()    return group_avg_spectra, cropped_axisdef avg_y_block(gcms_df):    """    Average the Y block (GC-MS or metadata) across replicate samples by group ID.    Parameters:    -----------    gcms_df : pd.DataFrame        Original target dataframe with replicate sample IDs as index (e.g., '1-1', '1-2').    Returns:    --------    pd.DataFrame        Group-averaged GC-MS data, indexed by group ID (e.g., '1', '2').    """    # Create a group column by removing suffix after '-'    df = gcms_df.copy()    df['Group'] = df.index.to_series().apply(lambda sid: sid.split("-")[0])        # Group by group ID and average    grouped_df = df.groupby("Group").mean()        return grouped_df